  ('diplomatic-535efab1-moex-00198', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-7f4830a9', 'sub-diplomatic-535efab1-04', NULL, 'single_choice', '關於1853至1856年克里米亞戰爭的陳述，下列敘述何者錯誤？', '["克里米亞戰爭也被稱為僧侶之間的戰爭", "主要參戰國為英、法、俄、鄂圖曼帝國和薩丁尼亞王國", "戰後法奧兩國合作緊密，建立軍事同盟", "戰後交戰國簽訂了巴黎和約，俄國喪失了在巴爾幹半島的控制權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "d5da3e634f0f", "answer_pdf_sha1": "0d2f9fd50581", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00199', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-7f4830a9', 'sub-diplomatic-535efab1-04', NULL, 'single_choice', '普魯士於1815年維也納會議後，推動「關稅同盟」（Zollverein），關於其影響，下列敘述何者錯誤？', '["普魯士企圖抵制了英法的經濟要脅", "普魯士企圖以關稅同盟連結維也納會議後所獲土地", "普魯士企圖創造居民共同記憶", "普魯士企圖強化內聚力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "d5da3e634f0f", "answer_pdf_sha1": "0d2f9fd50581", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00200', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-7f4830a9', 'sub-diplomatic-535efab1-04', NULL, 'single_choice', '關於1990年代初「冷戰」（ColdWar）結束原因的陳述，何者錯誤？', '["蘇聯領導人戈巴契夫（MikhailGorbachev）拒絕改革引發西方國家憎恨", "蘇聯因軍備競賽和軍事干預阿富汗戰爭幾近經濟崩潰", "東西德國的統一加速冷戰結束", "波羅的海三小國宣布脫離蘇聯獨立為冷戰結束開啟第一槍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "d5da3e634f0f", "answer_pdf_sha1": "0d2f9fd50581", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00201', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-7f4830a9', 'sub-diplomatic-535efab1-04', NULL, 'single_choice', '關於二次大戰後的柏林問題，下列敘述何者錯誤？', '["美英蘇三國於戰爭尚未結束前便已規劃占領德國，以防納粹或軍國主義東山再起", "1970年，英美法駐西德大使與蘇聯駐東德大使首次在柏林集會，討論如何解決「柏林問題」", "東德政府要求西方列強先給予法律承認，西德政府則認為蘇聯應至少接受西德與西柏林在經 濟、司法、幣制等多方面既有的關係", "當中共與美國開始外交接觸，蘇聯憤而暫停「柏林問題」的談判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "d5da3e634f0f", "answer_pdf_sha1": "0d2f9fd50581", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00202', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '關於我國憲法之權力分立原則，下列敘述何者正確？', '["總統不得發布任何替代或變更法律效力之命令，以免侵犯立法權", "立法院不得制定僅適用單一或少數對象之特殊類型法律，以免侵犯行政權", "行政院不得設置任何行政法院，以免侵犯司法權", "法院不得掌理審判及強制執行以外之事項，以免侵犯行政權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00203', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '關於政府採購得標廠商員工逾百者應進用一定比例原住民，未進用者令繳代金之規定，依司法院解釋 之意旨，下列敘述何者錯誤？', '["得標廠商於履約期間須進用一定比例之原住民，其營業自由因此受到限制", "得標廠商未達進用原住民之標準者須繳納代金，其財產權因此受到限制", "此規定於政府採購市場形成對於規模大小不同企業之差別待遇", "得標廠商於履約期間所能提供者多屬短期或不具技術性之工作，此規定難以達到增進原住民長期就 業之目的，違背比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00204', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '依司法院釋字第812號解釋，民國95年5月30日修正公布並自同年7月1日施行之竊盜犯贓物犯保安處分 條例第3條第1項規定：「18歲以上之竊盜犯、贓物犯，有犯罪之習慣者，得於刑之執行前，令入勞動 場所強制工作。」主要係侵害下列何項基本人權？', '["工作權", "財產權", "人身自由", "一般行為自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
